class Solution {
public:
    vector<bool> canMakePalindromeQueries(string s, vector<vector<int>>& queries) {
        int n = s.size();
        int half = n / 2;
        vector<int> freqL(26, 0), freqR(26, 0);
        for (int i = 0; i < half; ++i) freqL[s[i] - 'a']++;
        for (int i = half; i < n; ++i) freqR[s[i] - 'a']++;
        bool global = true;
        for (int i = 0; i < 26; ++i) if (freqL[i] != freqR[i]) global = false;

        vector<int> prefixL(half + 1, 0), prefixR(half + 1, 0);
        for (int i = 1; i <= half; ++i) {
            prefixL[i] = prefixL[i - 1] + (s[i - 1] == s[n - i] ? 0 : 1);
        }
        for (int i = 1; i <= half; ++i) {
            prefixR[i] = prefixR[i - 1] + (s[half - i] == s[half + i - 1] ? 0 : 1);
        }

        vector<bool> ans;
        for (auto& q : queries) {
            int a = q[0], b = q[1], c = q[2], d = q[3];
            if (!global) { ans.push_back(false); continue; }
            int l1 = a, r1 = b;
            int l2 = n - 1 - d, r2 = n - 1 - c;
            int left = max(l1, l2);
            int right = min(r1, r2);
            int mismatch = 0;
            if (left > right) {
                mismatch = prefixL[r1 + 1] - prefixL[l1] + prefixL[r2 + 1] - prefixL[l2];
            } else {
                mismatch = prefixL[l1] + (prefixL[half] - prefixL[r1 + 1]) + prefixL[l2] + (prefixL[half] - prefixL[r2 + 1]);
                mismatch += prefixL[right + 1] - prefixL[left];
            }
            ans.push_back(mismatch == 0);
        }
        return ans;
    }
};
